@tailwind base;
@tailwind components;
@tailwind utilities;

/* LIGHT MODE - Medical/Professional Blue Theme */
:root {
  --button-outline: rgba(0,0,0, .10);
  --badge-outline: rgba(0,0,0, .05);

  --opaque-button-border-intensity: -8;

  --elevate-1: rgba(0,0,0, .03);
  --elevate-2: rgba(0,0,0, .08);

  --background: 210 40% 98%;
  --foreground: 222 47% 11%;

  --border: 214 32% 91%;

  --card: 0 0% 100%;
  --card-foreground: 222 47% 11%;
  --card-border: 214 32% 91%;

  --sidebar: 210 40% 96%;
  --sidebar-foreground: 222 47% 11%;
  --sidebar-border: 214 32% 91%;
  --sidebar-primary: 217 91% 60%;
  --sidebar-primary-foreground: 0 0% 100%;
  --sidebar-accent: 217 91% 95%;
  --sidebar-accent-foreground: 217 91% 40%;
  --sidebar-ring: 217 91% 60%;

  --popover: 0 0% 100%;
  --popover-foreground: 222 47% 11%;
  --popover-border: 214 32% 91%;

  --primary: 174 72% 40%;
  --primary-foreground: 0 0% 100%;

  --secondary: 210 40% 96%;
  --secondary-foreground: 222 47% 11%;

  --muted: 210 40% 96%;
  --muted-foreground: 215 16% 47%;

  --accent: 174 72% 95%;
  --accent-foreground: 174 72% 30%;

  --destructive: 0 84% 60%;
  --destructive-foreground: 0 0% 100%;

  --input: 214 32% 91%;
  --ring: 217 91% 60%;
  --chart-1: 217 91% 60%;
  --chart-2: 173 58% 39%;
  --chart-3: 197 37% 24%;
  --chart-4: 43 74% 66%;
  --chart-5: 27 87% 67%;

  --font-sans: 'Inter', system-ui, sans-serif;
  --font-serif: 'Source Serif 4', Georgia, serif;
  --font-mono: 'JetBrains Mono', Menlo, monospace;
  --radius: .5rem;
  --shadow-2xs: 0 1px 2px 0 rgb(0 0 0 / 0.05);
  --shadow-xs: 0 1px 2px 0 rgb(0 0 0 / 0.05);
  --shadow-sm: 0 1px 3px 0 rgb(0 0 0 / 0.1), 0 1px 2px -1px rgb(0 0 0 / 0.1);
  --shadow: 0 1px 3px 0 rgb(0 0 0 / 0.1), 0 1px 2px -1px rgb(0 0 0 / 0.1);
  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);
  --shadow-xl: 0 20px 25px -5px rgb(0 0 0 / 0.1), 0 8px 10px -6px rgb(0 0 0 / 0.1);
  --shadow-2xl: 0 25px 50px -12px rgb(0 0 0 / 0.25);
  --tracking-normal: 0em;
  --spacing: 0.25rem;

  --sidebar-primary-border: hsl(var(--sidebar-primary));
  --sidebar-primary-border: hsl(from hsl(var(--sidebar-primary)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
  --sidebar-accent-border: hsl(var(--sidebar-accent));
  --sidebar-accent-border: hsl(from hsl(var(--sidebar-accent)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
  --primary-border: hsl(var(--primary));
  --primary-border: hsl(from hsl(var(--primary)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
  --secondary-border: hsl(var(--secondary));
  --secondary-border: hsl(from hsl(var(--secondary)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
  --muted-border: hsl(var(--muted));
  --muted-border: hsl(from hsl(var(--muted)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
  --accent-border: hsl(var(--accent));
  --accent-border: hsl(from hsl(var(--accent)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
  --destructive-border: hsl(var(--destructive));
  --destructive-border: hsl(from hsl(var(--destructive)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
}

/* DARK MODE */
.dark {
  --button-outline: rgba(255,255,255, .10);
  --badge-outline: rgba(255,255,255, .05);

  --opaque-button-border-intensity: 9;

  --elevate-1: rgba(255,255,255, .04);
  --elevate-2: rgba(255,255,255, .09);

  --background: 222 47% 6%;
  --foreground: 210 40% 98%;

  --border: 217 33% 17%;

  --card: 222 47% 9%;
  --card-foreground: 210 40% 98%;
  --card-border: 217 33% 17%;

  --sidebar: 222 47% 8%;
  --sidebar-foreground: 210 40% 98%;
  --sidebar-border: 217 33% 17%;
  --sidebar-primary: 217 91% 60%;
  --sidebar-primary-foreground: 0 0% 100%;
  --sidebar-accent: 217 91% 15%;
  --sidebar-accent-foreground: 217 91% 75%;
  --sidebar-ring: 217 91% 60%;

  --popover: 222 47% 9%;
  --popover-foreground: 210 40% 98%;
  --popover-border: 217 33% 17%;

  --primary: 174 72% 40%;
  --primary-foreground: 0 0% 100%;

  --secondary: 217 33% 17%;
  --secondary-foreground: 210 40% 98%;

  --muted: 217 33% 17%;
  --muted-foreground: 215 20% 65%;

  --accent: 174 72% 20%;
  --accent-foreground: 174 72% 75%;

  --destructive: 0 63% 45%;
  --destructive-foreground: 0 0% 100%;

  --input: 217 33% 22%;
  --ring: 217 91% 60%;
  --chart-1: 217 91% 60%;
  --chart-2: 173 58% 39%;
  --chart-3: 197 37% 54%;
  --chart-4: 43 74% 66%;
  --chart-5: 27 87% 67%;

  --shadow-2xs: 0 1px 2px 0 rgb(0 0 0 / 0.2);
  --shadow-xs: 0 1px 2px 0 rgb(0 0 0 / 0.2);
  --shadow-sm: 0 1px 3px 0 rgb(0 0 0 / 0.3), 0 1px 2px -1px rgb(0 0 0 / 0.3);
  --shadow: 0 1px 3px 0 rgb(0 0 0 / 0.3), 0 1px 2px -1px rgb(0 0 0 / 0.3);
  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.3), 0 2px 4px -2px rgb(0 0 0 / 0.3);
  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.3), 0 4px 6px -4px rgb(0 0 0 / 0.3);
  --shadow-xl: 0 20px 25px -5px rgb(0 0 0 / 0.3), 0 8px 10px -6px rgb(0 0 0 / 0.3);
  --shadow-2xl: 0 25px 50px -12px rgb(0 0 0 / 0.5);
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply font-sans antialiased bg-background text-foreground;
  }
}

@layer utilities {
  input[type="search"]::-webkit-search-cancel-button {
    @apply hidden;
  }

  [contenteditable][data-placeholder]:empty::before {
    content: attr(data-placeholder);
    color: hsl(var(--muted-foreground));
    pointer-events: none;
  }

  .no-default-hover-elevate {}
  .no-default-active-elevate {}

  .toggle-elevate::before,
  .toggle-elevate-2::before {
    content: "";
    pointer-events: none;
    position: absolute;
    inset: 0px;
    border-radius: inherit;
    z-index: -1;
  }

  .toggle-elevate.toggle-elevated::before {
    background-color: var(--elevate-2);
  }

  .border.toggle-elevate::before {
    inset: -1px;
  }

  .hover-elevate:not(.no-default-hover-elevate),
  .active-elevate:not(.no-default-active-elevate),
  .hover-elevate-2:not(.no-default-hover-elevate),
  .active-elevate-2:not(.no-default-active-elevate) {
    position: relative;
    z-index: 0;
  }

  .hover-elevate:not(.no-default-hover-elevate)::after,
  .active-elevate:not(.no-default-active-elevate)::after,
  .hover-elevate-2:not(.no-default-hover-elevate)::after,
  .active-elevate-2:not(.no-default-active-elevate)::after {
    content: "";
    pointer-events: none;
    position: absolute;
    inset: 0px;
    border-radius: inherit;
    z-index: 999;
  }

  .hover-elevate:hover:not(.no-default-hover-elevate)::after,
  .active-elevate:active:not(.no-default-active-elevate)::after {
    background-color: var(--elevate-1);
  }

  .hover-elevate-2:hover:not(.no-default-hover-elevate)::after,
  .active-elevate-2:active:not(.no-default-active-elevate)::after {
    background-color: var(--elevate-2);
  }

  .border.hover-elevate:not(.no-hover-interaction-elevate)::after,
  .border.active-elevate:not(.no-active-interaction-elevate)::after,
  .border.hover-elevate-2:not(.no-hover-interaction-elevate)::after,
  .border.active-elevate-2:not(.no-active-interaction-elevate)::after,
  .border.hover-elevate:not(.no-hover-interaction-elevate)::after {
    inset: -1px;
  }

  .prose-evidence {
    @apply prose prose-slate dark:prose-invert max-w-none;
  }

  .prose-evidence p {
    @apply mb-4 leading-relaxed;
  }

  .prose-evidence h1,
  .prose-evidence h2,
  .prose-evidence h3 {
    @apply font-semibold text-foreground mt-6 mb-3;
  }

  .prose-evidence ul,
  .prose-evidence ol {
    @apply my-4 pl-6;
  }

  .prose-evidence li {
    @apply mb-2;
  }

  .prose-evidence strong {
    @apply font-semibold text-foreground;
  }

  .prose-evidence a {
    @apply text-primary hover:underline;
  }

  .prose-evidence code {
    @apply bg-muted px-1.5 py-0.5 rounded text-sm;
  }

  .prose-evidence blockquote {
    @apply border-l-4 border-primary/30 pl-4 italic text-muted-foreground;
  }

  .citation-link {
    @apply inline-flex items-center justify-center w-5 h-5 text-xs font-medium bg-primary/10 text-primary rounded-full hover:bg-primary/20 transition-colors cursor-pointer align-super;
  }
}

@keyframes pulse-subtle {
  0%, 100% {
    opacity: 1;
  }
  50% {
    opacity: 0.7;
  }
}

.animate-pulse-subtle {
  animation: pulse-subtle 2s ease-in-out infinite;
}

@keyframes gradient-shift {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

.animate-gradient {
  background-size: 200% 200%;
  animation: gradient-shift 6s ease infinite;
}

@keyframes float-in {
  from {
    opacity: 0;
    transform: translateY(16px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.animate-float-in {
  animation: float-in 0.6s ease-out forwards;
  opacity: 0;
}

.animate-float-in-delay-1 { animation-delay: 0.1s; }
.animate-float-in-delay-2 { animation-delay: 0.2s; }
.animate-float-in-delay-3 { animation-delay: 0.3s; }
.animate-float-in-delay-4 { animation-delay: 0.4s; }

@keyframes glow-pulse {
  0%, 100% { opacity: 0.4; }
  50% { opacity: 0.7; }
}

.ambient-glow {
  position: absolute;
  border-radius: 9999px;
  filter: blur(80px);
  animation: glow-pulse 4s ease-in-out infinite;
  pointer-events: none;
}

.text-gradient-brand {
  background: linear-gradient(135deg, hsl(var(--primary)), hsl(217, 91%, 60%), hsl(var(--primary)));
  background-size: 200% 200%;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  animation: gradient-shift 4s ease infinite;
}

.glass-panel {
  background: hsl(var(--card) / 0.7);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

@keyframes shimmer {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}

.shimmer::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(90deg, transparent, hsl(var(--primary) / 0.15), transparent);
  animation: shimmer 1.5s ease-in-out infinite;
}

.shimmer {
  position: relative;
}

@keyframes thinking {
  0%, 20% { content: ""; }
  40% { content: "."; }
  60% { content: ".."; }
  80%, 100% { content: "..."; }
}

.thinking-dots::after {
  content: "";
  animation: thinking 1.5s infinite;
}

@keyframes skeleton-shimmer {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}

.skeleton-shimmer {
  background: linear-gradient(
    90deg,
    hsl(var(--muted)) 25%,
    hsl(var(--muted-foreground) / 0.08) 50%,
    hsl(var(--muted)) 75%
  );
  background-size: 200% 100%;
  animation: skeleton-shimmer 1.8s ease-in-out infinite;
}

/* Mobile/Tablet Touch Optimization */
@media (pointer: coarse) {
  .touch-target {
    min-height: 44px;
    min-width: 44px;
  }

  .touch-spacing {
    @apply p-3;
  }

  .touch-button {
    @apply min-h-[44px] px-4;
  }

  .touch-input {
    @apply min-h-[44px] text-base;
  }
}

/* Tablet-specific styles (768px - 1024px) */
@media (min-width: 768px) and (max-width: 1023px) {
  .tablet-layout {
    @apply px-6;
  }

  .tablet-grid {
    @apply grid-cols-2;
  }

  .tablet-text {
    @apply text-lg;
  }
}

/* Mobile bottom navigation */
.mobile-bottom-nav {
  @apply fixed bottom-0 left-0 right-0 z-50 border-t safe-area-pb;
}

/* Safe area padding for notched devices */
.safe-area-pb {
  padding-bottom: env(safe-area-inset-bottom, 0px);
}

.safe-area-pt {
  padding-top: env(safe-area-inset-top, 0px);
}

/* Full-width drawer for mobile clinical tools */
@media (max-width: 767px) {
  .clinical-tools-mobile {
    @apply fixed inset-x-0 bottom-0 z-50 rounded-t-2xl;
    max-height: 70vh;
  }
}

/* Larger touch targets for clinical buttons */
@media (pointer: coarse) {
  .clinical-tool-btn {
    @apply min-h-[48px] text-sm;
  }

  .clinical-input {
    @apply min-h-[44px] text-base;
  }
}

