import express, { type Request, Response, NextFunction } from "express";
import { registerRoutes } from "./routes";
import { serveStatic } from "./static";
import { createServer } from "http";
import { spawn, ChildProcess } from "child_process";

let pythonProcess: ChildProcess | null = null;

async function waitForPythonHealth(maxWaitMs = 120000): Promise<boolean> {
  const start = Date.now();
  const interval = 2000;
  while (Date.now() - start < maxWaitMs) {
    try {
      const resp = await fetch("http://localhost:8000/health", { signal: AbortSignal.timeout(3000) });
      if (resp.ok) {
        return true;
      }
    } catch {}
    await new Promise((r) => setTimeout(r, interval));
  }
  return false;
}

function startPythonAPI(): Promise<boolean> {
  return new Promise((resolve) => {
    console.log("Starting Python FastAPI backend on port 8000...");

    pythonProcess = spawn("python3", ["-m", "uvicorn", "app.main:app", "--host", "0.0.0.0", "--port", "8000"], {
      cwd: process.cwd(),
      stdio: ["ignore", "pipe", "pipe"],
      env: { ...process.env, PYTHONUNBUFFERED: "1" },
    });

    pythonProcess.stdout?.on("data", (data) => {
      const output = data.toString().trim();
      if (output) console.log(`[python] ${output}`);
    });

    pythonProcess.stderr?.on("data", (data) => {
      const output = data.toString().trim();
      if (output) console.log(`[python] ${output}`);
    });

    pythonProcess.on("error", (err) => {
      console.error("Failed to start Python API:", err.message);
      resolve(false);
    });

    pythonProcess.on("exit", (code) => {
      if (code !== 0 && code !== null) {
        console.error(`Python API exited with code ${code}`);
      }
    });

    waitForPythonHealth().then((healthy) => {
      if (healthy) {
        console.log("Python API started successfully (health check passed)");
        resolve(true);
      } else {
        console.error("Python API failed to become healthy within timeout");
        resolve(false);
      }
    });
  });
}

process.on("exit", () => {
  if (pythonProcess) {
    pythonProcess.kill();
  }
});

process.on("SIGINT", () => {
  if (pythonProcess) {
    pythonProcess.kill();
  }
  process.exit();
});

process.on("SIGTERM", () => {
  if (pythonProcess) {
    pythonProcess.kill();
  }
  process.exit();
});

const app = express();
const httpServer = createServer(app);

declare module "http" {
  interface IncomingMessage {
    rawBody: unknown;
  }
}

app.use(
  express.json({
    verify: (req, _res, buf) => {
      req.rawBody = buf;
    },
  }),
);

app.use(express.urlencoded({ extended: false }));

export function log(message: string, source = "express") {
  const formattedTime = new Date().toLocaleTimeString("en-US", {
    hour: "numeric",
    minute: "2-digit",
    second: "2-digit",
    hour12: true,
  });

  console.log(`${formattedTime} [${source}] ${message}`);
}

app.use((req, res, next) => {
  const start = Date.now();
  const path = req.path;
  let capturedJsonResponse: Record<string, any> | undefined = undefined;

  const originalResJson = res.json;
  res.json = function (bodyJson, ...args) {
    capturedJsonResponse = bodyJson;
    return originalResJson.apply(res, [bodyJson, ...args]);
  };

  res.on("finish", () => {
    const duration = Date.now() - start;
    if (path.startsWith("/api")) {
      let logLine = `${req.method} ${path} ${res.statusCode} in ${duration}ms`;
      if (capturedJsonResponse) {
        logLine += ` :: ${JSON.stringify(capturedJsonResponse)}`;
      }

      log(logLine);
    }
  });

  next();
});

(async () => {
  // Start Python FastAPI backend
  await startPythonAPI();

  await registerRoutes(httpServer, app);

  app.use((err: any, _req: Request, res: Response, next: NextFunction) => {
    const status = err.status || err.statusCode || 500;
    const message = err.message || "Internal Server Error";

    console.error("Internal Server Error:", err);

    if (res.headersSent) {
      return next(err);
    }

    return res.status(status).json({ message });
  });

  // importantly only setup vite in development and after
  // setting up all the other routes so the catch-all route
  // doesn't interfere with the other routes
  if (process.env.NODE_ENV === "production") {
    serveStatic(app);
  } else {
    const { setupVite } = await import("./vite");
    await setupVite(httpServer, app);
  }

  // ALWAYS serve the app on the port specified in the environment variable PORT
  // Other ports are firewalled. Default to 5000 if not specified.
  // this serves both the API and the client.
  // It is the only port that is not firewalled.
  const port = parseInt(process.env.PORT || "5000", 10);
  httpServer.listen(
    {
      port,
      host: "0.0.0.0",
      reusePort: true,
    },
    () => {
      log(`serving on port ${port}`);
    },
  );
})();

