function VoiceTranscriptionForm() {
  const { toast } = useToast();
  const [isRecording, setIsRecording] = useState(false);
  const [mediaRecorder, setMediaRecorder] = useState<MediaRecorder | null>(null);
  const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
  const [transcript, setTranscript] = useState("");

  const mutation = useMutation({
    mutationFn: async (blob: Blob) => {
      const formData = new FormData();
      formData.append("file", blob, "recording.webm");

      const res = await fetch("/api/voice/transcribe", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${getToken()}`,
        },
        body: formData,
      });

      if (!res.ok) throw new Error("Transcription failed");
      return res.json() as Promise<{ text: string }>;
    },
    onSuccess: (data) => {
      setTranscript(data.text);
      toast({ title: "Audio transcribed successfully" });
    },
    onError: () => {
      toast({ title: "Transcription failed", variant: "destructive" });
    },
  });

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];

      recorder.ondataavailable = (e) => chunks.push(e.data);
      recorder.onstop = () => {
        const blob = new Blob(chunks, { type: "audio/webm" });
        setAudioBlob(blob);
        stream.getTracks().forEach(track => track.stop());
      };

      recorder.start();
      setMediaRecorder(recorder);
      setIsRecording(true);
    } catch (err) {
      toast({ title: "Could not access microphone", variant: "destructive" });
    }
  };

  const stopRecording = () => {
    if (mediaRecorder) {
      mediaRecorder.stop();
      setIsRecording(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setAudioBlob(file);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col items-center gap-4 p-8 border-2 border-dashed rounded-lg">
        <div className="flex gap-4">
          <Button 
            size="lg"
            variant={isRecording ? "destructive" : "default"}
            onClick={isRecording ? stopRecording : startRecording}
            data-testid="button-record"
          >
            {isRecording ? <MicOff className="mr-2 h-5 w-5" /> : <Mic className="mr-2 h-5 w-5" />}
            {isRecording ? "Stop Recording" : "Start Recording"}
          </Button>
        </div>

        <div className="text-sm text-muted-foreground">or</div>

        <div>
          <Input 
            type="file" 
            accept="audio/*" 
            onChange={handleFileUpload}
            data-testid="input-audio-file"
          />
        </div>

        {audioBlob && (
          <div className="flex flex-col items-center gap-2">
            <audio src={URL.createObjectURL(audioBlob)} controls />
            <Button onClick={() => mutation.mutate(audioBlob)} disabled={mutation.isPending} data-testid="button-transcribe">
              {mutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Transcribe Audio
            </Button>
          </div>
        )}
      </div>

      {transcript && (
        <Card>
          <CardHeader className="flex flex-row items-center justify-between gap-4">
            <CardTitle>Transcript</CardTitle>
            <CopyButton text={transcript} />
          </CardHeader>
          <CardContent>
            <div className="whitespace-pre-wrap">{transcript}</div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

