import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  Search, BookOpen, Shield, Sparkles, ArrowRight, ArrowLeft, X
} from "lucide-react";

const ONBOARDING_KEY = "aestheticite_onboarded";

interface OnboardingStep {
  icon: typeof Search;
  title: string;
  description: string;
  detail: string;
}

const steps: OnboardingStep[] = [
  {
    icon: Search,
    title: "Ask any clinical question",
    description: "Type a question in natural language — in any of 25 supported languages.",
    detail: "AesthetiCite searches 217,000+ peer-reviewed papers and returns evidence-grounded answers with inline citations.",
  },
  {
    icon: Shield,
    title: "Every claim is cited",
    description: "Strict citation discipline: no citation = no claim.",
    detail: "Evidence is tiered by quality (Guidelines, RCTs, Case Reports) and each answer includes an ACI confidence score from 0 to 10.",
  },
  {
    icon: BookOpen,
    title: "Enhanced & DeepConsult modes",
    description: "Toggle Enhanced mode for advanced evidence analysis, or ask complex questions for PhD-level synthesis.",
    detail: "Enhanced mode adds evidence tiering, conflict detection, and claim-level verification. DeepConsult provides multi-study synthesis.",
  },
  {
    icon: Sparkles,
    title: "Tools & Export",
    description: "Clinical calculators, PDF export, voice input, and favorites — all built in.",
    detail: "Access BMI, BSA, eGFR calculators from the side panel. Export answers as PDF reports or share them with colleagues.",
  },
];

export function OnboardingDialog() {
  const [open, setOpen] = useState(false);
  const [step, setStep] = useState(0);

  useEffect(() => {
    const done = localStorage.getItem(ONBOARDING_KEY);
    if (!done) {
      const timer = setTimeout(() => setOpen(true), 600);
      return () => clearTimeout(timer);
    }
  }, []);

  useEffect(() => {
    if (!open) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === "Escape") dismiss();
    };
    document.addEventListener("keydown", handler);
    return () => document.removeEventListener("keydown", handler);
  }, [open]);

  function dismiss() {
    setOpen(false);
    localStorage.setItem(ONBOARDING_KEY, "1");
  }

  if (!open) return null;

  const current = steps[step];
  const Icon = current.icon;
  const isLast = step === steps.length - 1;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm" data-testid="onboarding-overlay">
      <Card className="relative w-full max-w-md mx-4 p-6 shadow-lg" data-testid="onboarding-card">
        <button
          onClick={dismiss}
          className="absolute top-3 right-3 text-muted-foreground hover-elevate rounded-md p-1"
          data-testid="button-close-onboarding"
        >
          <X className="w-4 h-4" />
        </button>

        <div className="flex items-center gap-2 mb-1">
          <Badge variant="secondary" className="text-[10px]">Getting Started</Badge>
          <span className="text-[10px] text-muted-foreground">{step + 1} of {steps.length}</span>
        </div>

        <div className="mt-4 flex items-center gap-3">
          <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center flex-shrink-0">
            <Icon className="w-5 h-5 text-primary" />
          </div>
          <h3 className="text-base font-semibold" data-testid="onboarding-title">{current.title}</h3>
        </div>

        <p className="mt-3 text-sm text-muted-foreground leading-6">{current.description}</p>
        <p className="mt-2 text-xs text-muted-foreground leading-5">{current.detail}</p>

        <div className="mt-6 flex items-center justify-between gap-2">
          <div className="flex gap-1.5">
            {steps.map((_, i) => (
              <div
                key={i}
                className={`w-2 h-2 rounded-full transition-colors ${i === step ? "bg-primary" : "bg-muted"}`}
                data-testid={`onboarding-dot-${i}`}
              />
            ))}
          </div>

          <div className="flex items-center gap-2">
            {step > 0 && (
              <Button variant="ghost" size="sm" onClick={() => setStep(step - 1)} data-testid="button-onboarding-back">
                <ArrowLeft className="w-3.5 h-3.5 mr-1" />
                Back
              </Button>
            )}
            {isLast ? (
              <Button size="sm" onClick={dismiss} data-testid="button-onboarding-done">
                Start searching
                <ArrowRight className="w-3.5 h-3.5 ml-1" />
              </Button>
            ) : (
              <Button size="sm" onClick={() => setStep(step + 1)} data-testid="button-onboarding-next">
                Next
                <ArrowRight className="w-3.5 h-3.5 ml-1" />
              </Button>
            )}
          </div>
        </div>

        <button
          onClick={dismiss}
          className="mt-3 w-full text-center text-[11px] text-muted-foreground hover:underline"
          data-testid="button-skip-onboarding"
        >
          Skip tour
        </button>
      </Card>
    </div>
  );
}

